import { Component, Inject, OnDestroy, OnInit } from '@angular/core';
import { UntypedFormBuilder, UntypedFormGroup } from '@angular/forms';
import { MAT_DIALOG_DATA, MatDialogRef } from '@angular/material/dialog';
import { Users } from '../interfaces/users.model';
import { UserService } from '../users.service';
import { Subscription } from 'rxjs';
import { GroupsService } from '../../groups/groups.service';
import { UnitmasterService } from 'src/app/pages/setup/unitmaster/unitmaster.service';
import { PosmanagementService } from 'src/app/pages/productmanagement/posmanagement/posmanagement.service';

@Component({
  selector: 'ux-users-create-update',
  templateUrl: './users-create-update.component.html',
  styleUrls: ['./users-create-update.component.scss']
})
export class UsersCreateUpdateComponent implements OnInit, OnDestroy {
  groups_list = [];
  units_list = [];
  form: UntypedFormGroup;
  mode: 'create' | 'update' = 'create';
  dateformat_list = [
    { format: 'DD-MM-YYYY' },
    { format: 'DD/MM/YYYY' },
    { format: 'DD/MMM/YYYY' },
    { format: 'DD-MMM-YYYY' },
    { format: 'DD-MM-YY' },
    { format: 'DD/MM/YY' },
    { format: 'DD/MMM/YY' },
    { format: 'DD-MMM-YY' },
    { format: 'MM-DD-YYYY' },
    { format: 'MM/DD/YYYY' },
    { format: 'MMM/DD/YYYY' },
    { format: 'MMM-DD-YYYY' },
    { format: 'MM-DD-YY' },
    { format: 'MM/DD/YY' },
    { format: 'MMM/DD/YY' },
    { format: 'MMM-DD-YY' },
  ];
  timeformat_list = [
    { format: 'HH:MM:SS (AM/PM)', value: 'hh:mm:ss A' },
    { format: 'HH:MM (AM/PM)', value: 'hh:mm A' },
    { format: 'HH:MM:SS (24HR)', value: 'HH:mm:ss' },
    { format: 'HH:MM (24HR)', value: 'HH:mm' },
  ];

  constructor(@Inject(MAT_DIALOG_DATA) public defaults: any,
    private dialogRef: MatDialogRef<UsersCreateUpdateComponent>,
    private fb: UntypedFormBuilder,
    private usersService: UserService,
    private groupService: GroupsService,
    private unitService: UnitmasterService,
    private posmanagementService: PosmanagementService
  ) {
  }

  group_subscription: Subscription;
  unit_subscription: Subscription;
  activity_subscription: Subscription;
  ngOnInit() {
    this.groupService.getAllGroups().subscribe();

    this.group_subscription = this.groupService.groupsChanged
      .subscribe(
        (groups: any[]) => {
          this.groups_list = groups;
        }
      );

    this.unitService.getAllUnitmaster().subscribe();

    this.unit_subscription = this.unitService.unitmasterChanged
      .subscribe(
        (units: any[]) => {
          this.units_list = units;
          console.log(this.units_list)
        }
      );

    if (this.defaults) {
      this.mode = 'update';
      //get the activities by Unit ID
      this.getActivitiesByUnit(this.defaults.unit_id._id);
    } else {
      this.defaults = {} as Users;
    }

    this.form = this.fb.group({
      user_id: this.defaults._id || '',
      first_name: this.defaults.first_name,
      last_name: [this.defaults.last_name || ''],
      mobile: [this.defaults.mobile || ''],
      email: [this.defaults.email || ''],
      group_id: [(this.defaults.group_id && this.defaults.group_id._id) || ''],
      unit_id: [(this.defaults.unit_id && this.defaults.unit_id._id) || ''],
      activity_id: [(this.defaults.activity_id && this.defaults.activity_id._id) || ''],
      date_format: [this.defaults.date_format || ''],
      time_format: [this.defaults.time_format || ''],
      status: this.defaults.status || '1'
    });

  }

  save() {
    if (this.mode === 'create') {
      this.createUsers();
    } else if (this.mode === 'update') {
      this.updateUsers();
    }
  }

  createUsers() {
    const users = this.form.value;
    this.dialogRef.close(users);
  }

  updateUsers() {
    const users = this.form.value;
    users._id = this.defaults._id;

    this.dialogRef.close(users);
  }

  isCreateMode() {
    return this.mode === 'create';
  }

  isUpdateMode() {
    return this.mode === 'update';
  }

  activities_list = [];
  onUnitChange(event: any) {
    this.getActivitiesByUnit(event.value);
  }

  private getActivitiesByUnit(unit_id: string) {
    this.posmanagementService.getActivitiesByUnit(unit_id)
      .then((res: any) => {
        console.log(res);
        if (res.messagecode === 100) {
          if (res.posdata.activities.length > 0) {
            this.activities_list = res.posdata.activities.filter(x => x.selected);
            console.log(this.activities_list);
          } else {
            this.activities_list = [];
          }
        }
      })
      .catch((err: any) => {
      });
  }

  ngOnDestroy(): void {
    if (this.group_subscription) {
      this.group_subscription.unsubscribe();
    }
  }
}
